class BaseButton extends React.Component { /* ... */ }
class PrimaryButton extends BaseButton { /* ... */ }

// 建議的組合寫法：用 props／children 傳遞客製化內容
function Button({ variant, children }) {
  return <button className={variant}>{children}</button>;
}
function PrimaryButton({ children }) {
  return <Button variant="primary">{children}</Button>;
}

function SliderPanel() {
  const sliderRef = useRef(null);

  function handleReset() {
    sliderRef.current.reset(); // 呼叫自訂元素提供的命令式方法
  }

  return (
    <div>
      <fancy-slider ref={sliderRef} min={0} max={100}></fancy-slider>
      <button onClick={handleReset}>重設</button>
    </div>
  );
}

const TabsContext = createContext(null);

function Tabs({ children }) {
  return (
    <TabsContext.Provider value={{ active: 0 }}>
      {children}
    </TabsContext.Provider>
  );
}
function Tab({ index, label }) {
  const { active } = useContext(TabsContext);
  return <span>{label}{active === index ? "(選中)" : ""}</span>;
}
Tabs.Tab = Tab;

console.log(renderToStaticMarkup(
  <Tabs>
    <Tabs.Tab index={0} label="A" />
    <Tabs.Tab index={1} label="B" />
  </Tabs>
));

